import{_ as e,c as o,o as a,a1 as n}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"入门: 本地 AI 网关 | Antigravity-Manager","description":"学习 Antigravity-Manager 的核心定位。它是一个本地 AI 网关，提供统一的 OpenAI/Anthropic/Gemini 兼容接口。","frontmatter":{"title":"入门: 本地 AI 网关 | Antigravity-Manager","sidebarTitle":"入门","subtitle":"入门: 本地 AI 网关 | Antigravity-Manager","description":"学习 Antigravity-Manager 的核心定位。它是一个本地 AI 网关，提供统一的 OpenAI/Anthropic/Gemini 兼容接口。","tags":["Getting Started","Concepts","Local Gateway","API Proxy"],"prerequisite":[],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/start/getting-started/index.md","filePath":"lbjlaq/Antigravity-Manager/start/getting-started/index.md"}'),r={name:"lbjlaq/Antigravity-Manager/start/getting-started/index.md"};function i(s,t,l,c,d,u){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="what-is-antigravity-tools-transforming-accounts-protocols-into-a-local-ai-gateway" tabindex="-1">What is Antigravity Tools: Transforming &quot;Accounts + Protocols&quot; into a Local AI Gateway <a class="header-anchor" href="#what-is-antigravity-tools-transforming-accounts-protocols-into-a-local-ai-gateway" aria-label="Permalink to &quot;What is Antigravity Tools: Transforming &quot;Accounts + Protocols&quot; into a Local AI Gateway&quot;">​</a></h1><p>The barrier to entry for many AI clients/SDKs isn&#39;t &quot;knowing how to call APIs,&quot; but rather &quot;which provider protocol to integrate with, how to manage multiple accounts, and how to make failures recover automatically.&quot; Antigravity Tools aims to consolidate these three tasks into a single local gateway.</p><h2 id="what-is-antigravity-tools" tabindex="-1">What is Antigravity Tools? <a class="header-anchor" href="#what-is-antigravity-tools" aria-label="Permalink to &quot;What is Antigravity Tools?&quot;">​</a></h2><p><strong>Antigravity Tools</strong> is a desktop application: you manage accounts and configurations in the GUI, and it starts an HTTP reverse proxy service on your local machine that forwards requests from different providers/protocols to upstream and converts responses back to the format your client expects.</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Clearly articulate what problem Antigravity Tools solves (and what it doesn&#39;t)</li><li>Recognize its core components: GUI, account pool, HTTP reverse proxy gateway, protocol adaptation</li><li>Understand the default security boundaries (127.0.0.1, port, auth mode) and when you need to change them</li><li>Know which chapter to go to next: installation, adding accounts, starting the reverse proxy, connecting clients</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><p>You might have encountered these frustrations:</p><ul><li>The same client needs to support OpenAI/Anthropic/Gemini protocols, and configuration often gets messy</li><li>You have multiple accounts, but switching, rotation, and rate-limited retries are all manual</li><li>When requests fail, you can only stare at logs and guess whether it&#39;s &quot;account invalid&quot; or &quot;upstream rate limit/quota exhausted&quot;</li></ul><p>Antigravity Tools&#39; goal is to handle these &quot;edge tasks&quot; inside a local gateway, so your client/SDK only needs to care about one thing: sending requests to localhost.</p><h2 id="core-approach" tabindex="-1">Core Approach <a class="header-anchor" href="#core-approach" aria-label="Permalink to &quot;Core Approach&quot;">​</a></h2><p>You can think of it as a local &quot;AI dispatch gateway&quot; composed of three layers:</p><ol><li>GUI (Desktop Application)</li></ol><ul><li>Responsible for letting you manage accounts, configurations, monitoring, and statistics.</li><li>Main pages include: Dashboard, Accounts, API Proxy, Monitor, Token Stats, Settings.</li></ul><ol start="2"><li>HTTP Reverse Proxy Service (Axum Server)</li></ol><ul><li>Responsible for exposing endpoints for multiple protocols externally and forwarding requests to the corresponding handler.</li><li>The reverse proxy service layers authentication, middleware monitoring, CORS, Trace, etc.</li></ul><ol start="3"><li>Account Pool and Scheduling (TokenManager, etc.)</li></ol><ul><li>Responsible for selecting available accounts from the local account pool, refreshing tokens when needed, and handling rotation and self-healing.</li></ul><div class="info custom-block"><p class="custom-block-title">What does &quot;local gateway&quot; mean?</p><p>&quot;Local&quot; here is literal: the service runs on your own machine. Your clients (Claude Code, OpenAI SDK, various third-party clients) point their Base URL to <code>http://127.0.0.1:&lt;port&gt;</code>, requests first hit your local machine, then are forwarded to upstream by Antigravity Tools.</p></div><h2 id="what-endpoints-does-it-expose" tabindex="-1">What Endpoints Does It Expose? <a class="header-anchor" href="#what-endpoints-does-it-expose" aria-label="Permalink to &quot;What Endpoints Does It Expose?&quot;">​</a></h2><p>The reverse proxy service registers multiple protocol endpoints in a Router. Remember these &quot;entry points&quot; for now:</p><ul><li>OpenAI-compatible: <code>/v1/chat/completions</code>, <code>/v1/completions</code>, <code>/v1/responses</code>, <code>/v1/models</code></li><li>Anthropic-compatible: <code>/v1/messages</code>, <code>/v1/messages/count_tokens</code></li><li>Gemini native: <code>/v1beta/models</code>, <code>/v1beta/models/:model</code>, <code>/v1beta/models/:model/countTokens</code></li><li>Health check: <code>GET /healthz</code></li></ul><p>If your client can integrate with any of these protocols, theoretically you can route requests to this local gateway by &quot;changing the Base URL.&quot;</p><h2 id="default-security-boundaries-don-t-skip" tabindex="-1">Default Security Boundaries (Don&#39;t Skip) <a class="header-anchor" href="#default-security-boundaries-don-t-skip" aria-label="Permalink to &quot;Default Security Boundaries (Don&#39;t Skip)&quot;">​</a></h2><p>The biggest pitfall with &quot;local reverse proxies&quot; isn&#39;t usually insufficient features—it&#39;s accidentally exposing them.</p><p>Remember these defaults first (all from default configuration):</p><ul><li>Default port: <code>8045</code></li><li>Default localhost-only access: <code>allow_lan_access=false</code>, listening address is <code>127.0.0.1</code></li><li>Default auth mode: <code>auth_mode=off</code> (doesn&#39;t require clients to send a key)</li><li>Default generates an <code>sk-...</code> format <code>api_key</code> (for you to enable when you need authentication)</li></ul><div class="warning custom-block"><p class="custom-block-title">When must you enable authentication?</p><p>As soon as you enable LAN access (<code>allow_lan_access=true</code>, listening address becomes <code>0.0.0.0</code>), you should simultaneously enable authentication and treat the API Key as a password.</p></div><h2 id="when-to-use-antigravity-tools" tabindex="-1">When to Use Antigravity Tools <a class="header-anchor" href="#when-to-use-antigravity-tools" aria-label="Permalink to &quot;When to Use Antigravity Tools&quot;">​</a></h2><p>It&#39;s better suited for these scenarios:</p><ul><li>You have multiple AI clients/SDKs and want them all to use a single Base URL</li><li>You need to converge different protocols (OpenAI/Anthropic/Gemini) into the same &quot;local exit&quot;</li><li>You have multiple accounts and want the system to handle rotation and stability</li></ul><p>If you just want to &quot;write two lines of code to directly call the official API&quot; and your accounts/protocols are fixed, it might be overkill.</p><h2 id="follow-along-establish-the-correct-usage-order-first" tabindex="-1">Follow Along: Establish the Correct Usage Order First <a class="header-anchor" href="#follow-along-establish-the-correct-usage-order-first" aria-label="Permalink to &quot;Follow Along: Establish the Correct Usage Order First&quot;">​</a></h2><p>This lesson doesn&#39;t teach detailed configuration—it just aligns the main sequence first to avoid getting stuck by skipping around.</p><h3 id="step-1-install-first-then-start" tabindex="-1">Step 1: Install First, Then Start <a class="header-anchor" href="#step-1-install-first-then-start" aria-label="Permalink to &quot;Step 1: Install First, Then Start&quot;">​</a></h3><p><strong>Why</strong> The desktop app handles account management and starting the reverse proxy service. Without it, there&#39;s no way to do OAuth or reverse proxying.</p><p>Go to the next chapter and complete installation following the README&#39;s installation method.</p><p><strong>What you should see</strong>: You can open Antigravity Tools and see the Dashboard page.</p><h3 id="step-2-add-at-least-one-account" tabindex="-1">Step 2: Add at Least One Account <a class="header-anchor" href="#step-2-add-at-least-one-account" aria-label="Permalink to &quot;Step 2: Add at Least One Account&quot;">​</a></h3><p><strong>Why</strong> The reverse proxy service needs to get an available identity from the account pool to send requests upstream. Without accounts, the gateway can&#39;t &quot;make calls on your behalf.&quot;</p><p>Go to the &quot;Adding Accounts&quot; chapter and add an account following the OAuth or Refresh Token flow.</p><p><strong>What you should see</strong>: Your account appears in the Accounts page, and you can see quota/status information.</p><h3 id="step-3-start-api-proxy-and-verify-with-healthz" tabindex="-1">Step 3: Start API Proxy and Verify with /healthz <a class="header-anchor" href="#step-3-start-api-proxy-and-verify-with-healthz" aria-label="Permalink to &quot;Step 3: Start API Proxy and Verify with /healthz&quot;">​</a></h3><p><strong>Why</strong> First use <code>GET /healthz</code> to verify &quot;the local service is running,&quot; then connect clients. Troubleshooting will be much simpler.</p><p>Go to the &quot;Start Local Reverse Proxy and Connect Your First Client&quot; chapter to complete the loop.</p><p><strong>What you should see</strong>: Your client/SDK can successfully get responses through the local Base URL.</p><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>What you might do (❌)</th><th>Recommended approach (✓)</th></tr></thead><tbody><tr><td>Want phone/another computer to access</td><td>Enable <code>allow_lan_access=true</code> directly without setting up authentication</td><td>Enable authentication simultaneously, and verify <code>GET /healthz</code> on LAN first</td></tr><tr><td>Client reports 404</td><td>Only change host/port, ignore how client concatenates <code>/v1</code></td><td>Confirm client&#39;s base_url concatenation strategy first, then decide if <code>/v1</code> prefix is needed</td></tr><tr><td>Start with Claude Code immediately</td><td>Connect complex client directly, don&#39;t know where to look when it fails</td><td>First get the minimal loop working: start Proxy -&gt; <code>GET /healthz</code> -&gt; then connect client</td></tr></tbody></table><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>Antigravity Tools&#39; positioning is &quot;desktop app + local HTTP reverse proxy gateway&quot;: GUI management, Axum provides multi-protocol endpoints</li><li>You need to treat it as local infrastructure: install first, then add accounts, then start Proxy, finally connect clients</li><li>Default listens on <code>127.0.0.1:8045</code> only; if exposing to LAN, enable authentication</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we complete the installation step: <strong><a href="./../installation/">Installation &amp; Upgrades: Best Desktop Installation Paths</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>The installation methods listed in the README (and their priority)</li><li>Upgrade entry points and handling common system blocks</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>Product positioning (local AI relay/protocol gap)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L35-L77" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>35-77</td></tr><tr><td>Router endpoint overview (OpenAI/Claude/Gemini/healthz)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L120-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>120-194</td></tr><tr><td>Default port/default localhost/default key and bind address logic</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L291" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-291</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>GUI page routing structure (Dashboard/Accounts/API Proxy/Monitor/Token Stats/Settings)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/App.tsx#L19-L48" target="_blank" rel="noreferrer"><code>src/App.tsx</code></a></td><td>19-48</td></tr></tbody></table><p><strong>Key defaults</strong>:</p><ul><li><code>ProxyConfig.port = 8045</code>: Reverse proxy service default port</li><li><code>ProxyConfig.allow_lan_access = false</code>: Default localhost-only access</li><li><code>ProxyAuthMode::default() = off</code>: Default no authentication required</li></ul></details>',55)])])}const g=e(r,[["render",i]]);export{p as __pageData,g as default};
